"use client"

import React, { useState } from "react"
import Header from "@/components/Header"
import ProductCard from "@/components/ProductCard"
import CartSidebar from "@/components/CartSidebar"
import PromoBanners from "@/components/PromoBanners"
import { products } from "@/components/data"

export interface CartItem {
 id: number
 name: string
 image: string
 price: number
 oldPrice?: number
 quantity: number
}

const CATEGORIES = [
 "постное меню",
 "23 февраля",
 "новинки",
 "эклеры",
 "пирожные",
 "торты",
 "хлеб",
 "слойка",
 "кексы и печенье",
 "случайный выбор",
]

export default function Home() {
 const [cart, setCart] = useState<CartItem[]>([])
 const [activeCategory, setActiveCategory] = useState("новинки")
 const [onlyDelivery, setOnlyDelivery] = useState(false)

 const addToCart = (product: typeof products[0]) => {
  setCart((prev) => {
   const found = prev.find((i) => i.id === product.id)
   if (found) return prev.map((i) => (i.id === product.id ? { ...i, quantity: i.quantity + 1 } : i))
   return [
    ...prev,
    {
     id: product.id,
     name: product.name,
     image: product.image ?? "",
     price: product.price,
     oldPrice: product.oldPrice,
     quantity: 1,
    },
   ]
  })
 }

 const updateQty = (id: number, delta: number) => {
  setCart((prev) =>
   prev
    .map((i) => (i.id === id ? { ...i, quantity: Math.max(0, i.quantity + delta) } : i))
    .filter((i) => i.quantity > 0)
  )
 }

 const total = cart.reduce((s, i) => s + i.price * i.quantity, 0)

 return (
  <div className="min-h-screen bg-white font-manrope selection:bg-meren-orange/20 selection:text-meren-black">
   <Header />

   <main className="mx-auto w-full max-w-[1800px] px-6 py-8">

    {/* ── Promo stories section ── */}
    <PromoBanners />

    {/* ── Category Chips & Controls ── */}
    <div className="sticky top-14 z-20 flex flex-col gap-4 bg-white/90 pb-4 pt-2 backdrop-blur-md">
     <div className="flex items-center justify-between gap-4">

      {/* Horizontal Categoroy Scroll */}
      <div className="smooth-scroll flex h-14 flex-1 items-center gap-2 overflow-x-auto">
       {CATEGORIES.map((cat) => (
        <button
         key={cat}
         onClick={() => setActiveCategory(cat)}
         className={`chip-btn ${activeCategory === cat
           ? "bg-meren-black text-white border-meren-black"
           : "bg-[#F5F5F7] text-meren-black hover:bg-[#EBEBF0]"
          }`}
        >
         {cat}
        </button>
       ))}
      </div>

      {/* Right side controls */}
      <div className="flex items-center gap-2">
       <div className="hidden sm:flex h-9 items-center gap-2 rounded-full bg-[#F5F5F7] px-4 border border-black/5">
        <span className="text-[10px] font-black uppercase text-meren-black opacity-60">Только доставка</span>
        <button
         onClick={() => setOnlyDelivery(!onlyDelivery)}
         className={`relative h-5 w-9 shrink-0 rounded-full transition-all duration-300 cursor-pointer border-none ${onlyDelivery ? "bg-meren-orange shadow-orange" : "bg-black/10"
          }`}
        >
         <div
          className={`absolute top-0.5 h-4 w-4 rounded-full bg-white shadow-sm transition-all duration-300 ${onlyDelivery ? "left-[18px]" : "left-0.5"
           }`}
         />
        </button>
       </div>
       <button className="chip-btn bg-white hover:bg-[#F5F5F7]">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" className="mr-2">
         <path d="M3 6h18M6 12h12M10 18h4" />
        </svg>
        Фильтры
       </button>
      </div>
     </div>
    </div>

    <div className="flex gap-8 items-start mt-4">
     {/* ── Main Product Grid ── */}
     <section className="flex-1">
      <div className="mb-6 flex items-baseline gap-2 px-2">
       <h1 className="text-[28px] font-black tracking-tighter text-meren-black lowercase">{activeCategory}</h1>
       <span className="text-xs font-bold text-[#AEAEB2]">{products.length} товаров</span>
      </div>

      {/* Dense 6-column Grid for Wow layout */}
      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4">
       {products.map((p) => (
        <ProductCard key={p.id} {...p} image={p.image ?? ""} onAdd={() => addToCart(p)} />
       ))}

       {/* Explorer Tile */}
       <div className="flex min-h-[300px] items-center justify-center rounded-2xl bg-[#F5F5F7] border border-dashed border-black/10 transition-colors hover:bg-[#EBEBF0] cursor-pointer group">
        <div className="flex flex-col items-center gap-2">
         <span className="text-[11px] font-black text-[#AEAEB2] uppercase tracking-[0.2em] group-hover:text-meren-black transition-colors">Смотреть всё</span>
         <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#AEAEB2" strokeWidth="3" className="group-hover:stroke-meren-black transition-colors">
          <path d="M5 12h14M12 5l7 7-7 7" />
         </svg>
        </div>
       </div>
      </div>
     </section>

     {/* ── Cart Sidebar Sidebar (Balanced) ── */}
     {cart.length > 0 && (
      <aside className="hidden lg:block sticky top-24 w-[340px] shrink-0 h-[calc(100vh-120px)] overflow-y-auto smooth-scroll transition-all anim-slide-up">
       <CartSidebar cart={cart} onUpdateQuantity={updateQty} total={total} />
      </aside>
     )}
    </div>
   </main>
  </div>
 )
}
