"use client"
import React from "react"
import { CartItem } from "@/app/page"

interface Props {
 cart: CartItem[]
 onUpdateQuantity: (id: number, delta: number) => void
 total: number
}

/* Sad bag illustration — inline SVG */
const SadBag = () => (
 <svg width="100" height="120" viewBox="0 0 100 120" fill="none" xmlns="http://www.w3.org/2000/svg">
  {/* Bag body */}
  <rect x="14" y="36" width="72" height="80" rx="6" fill="#F0F0F0" />
  {/* Bag handle */}
  <path d="M36 36 C36 20 64 20 64 36" stroke="#D0D0D0" strokeWidth="4" fill="none" strokeLinecap="round" />
  {/* Face — × left eye */}
  <path d="M37 68 L43 74 M43 68 L37 74" stroke="#B0B0B0" strokeWidth="3" strokeLinecap="round" />
  {/* Face — × right eye */}
  <path d="M57 68 L63 74 M63 68 L57 74" stroke="#B0B0B0" strokeWidth="3" strokeLinecap="round" />
  {/* Face — flat mouth */}
  <path d="M40 86 L60 86" stroke="#B0B0B0" strokeWidth="3" strokeLinecap="round" />
 </svg>
)

const CartSidebar: React.FC<Props> = ({ cart, onUpdateQuantity, total }) => {
 return (
  <div className="flex flex-col h-full bg-white rounded-[32px] overflow-hidden shadow-bold border border-black/5 font-manrope">

   {/* ── Top info bar ── */}
   <div className="flex items-center justify-between p-[18px_20px] border-b border-black/5">
    <span className="text-[17px] font-black tracking-[-0.035em] text-[#0F0F0F]">
     30–60 мин, 0–219₽
    </span>
    <button className="flex h-7 w-7 items-center justify-center rounded-full bg-transparent transition-colors hover:bg-black/5 cursor-pointer border-none">
     <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#AEAEB2" strokeWidth="2" strokeLinecap="round">
      <circle cx="12" cy="12" r="10" />
      <path d="M12 16v-4M12 8h.01" />
     </svg>
    </button>
   </div>

   {/* ── Body ── */}
   <div className="flex-1 flex flex-col min-h-0">
    {cart.length === 0 ? (
     /* ── Empty state ── */
     <div className="flex-1 flex flex-col items-center justify-center p-[40px_24px]">
      <SadBag />
      <p className="mt-5 text-sm font-medium text-[#3C3C43]/60 text-center leading-relaxed max-w-[200px]">
       В корзине пока ничего нет. Самое время наполнять её!
      </p>
     </div>
    ) : (
     /* ── Items ── */
     <div className="flex-1 overflow-y-auto px-4 pt-3 smooth-scroll">
      <div className="flex flex-col gap-3">
       {cart.map((item) => (
        <div key={item.id} className="flex items-center gap-2.5 p-2.5 bg-meren-bone rounded-2xl">
         {/* Thumbnail */}
         <div className="flex h-[50px] w-[50px] shrink-0 items-center justify-center overflow-hidden rounded-xl bg-white shadow-sm">
          <img src={item.image} alt="" className="h-4/5 w-4/5 object-contain mix-blend-multiply" />
         </div>

         {/* Name + qty */}
         <div className="flex-1 min-w-0 font-manrope">
          <p className="mb-1 text-[11px] font-bold leading-tight tracking-tight text-[#0F0F0F] line-clamp-2">
           {item.name}
          </p>

          {/* — N + */}
          <div className="inline-flex items-center rounded-lg border border-black/5 bg-white">
           <button
            onClick={() => onUpdateQuantity(item.id, -1)}
            className="flex h-6.5 w-6.5 items-center justify-center text-sm font-bold text-[#AEAEB2] transition-colors hover:text-meren-orange cursor-pointer border-none"
           >—</button>
           <span className="min-w-[14px] text-center text-xs font-black text-[#0F0F0F]">
            {item.quantity}
           </span>
           <button
            onClick={() => onUpdateQuantity(item.id, 1)}
            className="flex h-6.5 w-6.5 items-center justify-center text-sm font-bold text-[#AEAEB2] transition-colors hover:text-meren-orange cursor-pointer border-none"
           >+</button>
          </div>
         </div>

         {/* Price */}
         <div className="flex shrink-0 flex-col items-end">
          {item.oldPrice && (
           <span className="mb-px text-[10px] font-medium text-[#C7C7CC] line-through">
            {item.oldPrice * item.quantity}
           </span>
          )}
          <span className="text-sm font-black tracking-tight text-[#0F0F0F]">
           {item.price * item.quantity} ₽
          </span>
         </div>
        </div>
       ))}
      </div>

      {/* Total row */}
      <div className="mt-3 flex justify-between border-t border-black/5 p-[12px_6px]">
       <span className="text-xs font-bold text-[#8E8E93]">Итого</span>
       <span className="text-xl font-black tracking-tighter text-[#0F0F0F]">{total} ₽</span>
      </div>
     </div>
    )}
   </div>

   {/* ── Bottom button ── */}
   <div className="p-[12px_16px_18px]">
    <button
     disabled={cart.length === 0}
     className={`h-[50px] w-full items-center justify-center rounded-full text-[15px] font-bold tracking-tight transition-all duration-300 flex font-manrope ${cart.length === 0
       ? "bg-[#F2F2F7] text-[#AEAEB2] cursor-default"
       : "bg-meren-orange text-white shadow-[0_6px_20px_rgba(255,107,53,0.25)] hover:brightness-105 active:scale-95 cursor-pointer"
      } border-none`}
    >
     {cart.length === 0 ? "Добавьте что-нибудь" : "Продолжить"}
    </button>
   </div>

  </div>
 )
}

export default CartSidebar
